type DDoSGuardWebSocket = {
  close: () => void;
  onclose: ((event: unknown) => void) | null;
  onerror: ((event: unknown) => void) | null;
  onmessage: ((event: { data: unknown }) => void | Promise<void>) | null;
  onopen: (() => void) | null;
  send: (data: string) => void;
};

type DDoSGuardWebSocketConstructor = new (url: string) => DDoSGuardWebSocket;

type DDoSGuardFingerprint = {
  newFp: {
    adBlock: boolean;
    audioFp: string;
    availableHeight: number;
    availableWidth: number;
    canvasFp: string;
    canvasWinding: boolean;
    colorDepth: number;
    cpuClass: string;
    defaultHeight: number;
    defaultWidth: number;
    deviceMemory: number;
    fonts: string[];
    hardwareConcurrency: number;
    hasLiedLanguages: boolean;
    hasLiedResolution: boolean;
    isWebDriver: boolean;
    languages: string[];
    maxTouchPoints: number;
    pixelRatio: number;
    platform: string;
    plugins: string[];
    sensor: string[];
    touchSupportEvent: boolean;
    touchSupportStart: boolean;
    userAgent: string;
    webglAnisotropy: number;
    webglAntialiasing: boolean;
    webglFp: string;
    webglGPU: string;
    webglVendor: string;
  };
};

