const DDG_MARK_PAYLOAD = DDG_MARK_PAYLOAD_CHUNKS.join("");
const DDG_FINGERPRINT = JSON.parse(DDG_MARK_PAYLOAD) as DDoSGuardFingerprint;

export class DDoSGuardSolver {
  public static readonly desktopUserAgent =
    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36";

  private static readonly solvedHosts = new Map<string, number>();

  public static requestHeaders(extraHeaders: Record<string, string> = {}) {
    return {
      "User-Agent": this.desktopUserAgent,
      ...extraHeaders,
    };
  }

  public static async solve(targetURL: URL): Promise<boolean> {
    const origin = new URL("/", targetURL.href);
    const host = origin.hostname.toLowerCase();
    const cachedAt = this.solvedHosts.get(host) ?? 0;
    if (Date.now() - cachedAt < 10 * 60 * 1000) {
      return true;
    }

    ztoolkit.log(
      `ddos-guard: solving JS challenge for ${origin.hostname} with pure HTTP/WebSocket flow`,
    );

    await this.request(origin, "/", {
      accept: "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
    });
    await this.request(
      origin,
      "/.well-known/ddos-guard/js-challenge/index.css",
    );
    await this.request(origin, "/.well-known/ddos-guard/js-challenge/view.js");
    await this.request(origin, "/.well-known/ddos-guard/js-challenge/index.js");
    await this.request(
      origin,
      `/.well-known/ddos-guard/id/${this.randomID()}`,
      { accept: "image/avif,image/webp,*/*" },
    );
    await this.request(
      origin,
      "/.well-known/ddos-guard/js-challenge/keep_referer.js",
    );

    const mark = await this.request(origin, "/.well-known/ddos-guard/mark/", {
      body: DDG_MARK_PAYLOAD,
      headers: {
        "Content-Type": "text/plain;charset=UTF-8",
      },
      method: "POST",
    });
    if (mark.status && mark.status >= 400) {
      throw new Error(
        `DDoS-Guard mark failed: HTTP ${mark.status} ${mark.statusText ?? ""}`,
      );
    }

    const challenges = await this.runWebSocketChallenge(origin);
    await this.sleep(1200);
    this.solvedHosts.set(host, Date.now());
    ztoolkit.log(
      `ddos-guard: solved ${origin.hostname}; websocket challenge batches=${challenges}`,
    );
    return true;
  }

  private static async request(
    origin: URL,
    path: string,
    options: {
      accept?: string;
      body?: string;
      headers?: Record<string, string>;
      method?: "GET" | "POST";
    } = {},
  ) {
    const url = new URL(path, origin.href).href;
    return await Zotero.HTTP.request(options.method ?? "GET", url, {
      body: options.body,
      headers: this.requestHeaders({
        Accept: options.accept ?? "*/*",
        Referer: origin.href,
        ...options.headers,
      }),
      responseType: "text",
      successCodes: false,
    });
  }

  private static async runWebSocketChallenge(origin: URL): Promise<number> {
    const WebSocketCtor = (
      globalThis as unknown as { WebSocket?: DDoSGuardWebSocketConstructor }
    ).WebSocket;
    if (!WebSocketCtor) {
      throw new Error(
        "DDoS-Guard WebSocket API is not available in this Zotero context",
      );
    }

    const wsURL = `${origin.protocol === "https:" ? "wss:" : "ws:"}//${origin.host}/.well-known/ddos-guard/mark/ws`;
    return await new Promise<number>((resolve, reject) => {
      let batches = 0;
      let settled = false;
      const ws = new WebSocketCtor(wsURL);
      const timer = setTimeout(() => {
        if (settled) {
          return;
        }
        settled = true;
        try {
          ws.close();
        } catch (_error) {
          // Ignore close failures; timeout error is more useful.
        }
        reject(new Error("DDoS-Guard WebSocket challenge timed out"));
      }, 15000);

      const finish = () => {
        if (settled) {
          return;
        }
        settled = true;
        clearTimeout(timer);
        resolve(batches);
      };

      ws.onopen = () => undefined;
      ws.onerror = (event: unknown) => {
        if (settled) {
          return;
        }
        settled = true;
        clearTimeout(timer);
        reject(new Error(`DDoS-Guard WebSocket error: ${String(event)}`));
      };
      ws.onclose = () => finish();
      ws.onmessage = (event: { data: unknown }) => {
        const text = String(event.data ?? "");
        if (!text) {
          return;
        }
        let message: Record<string, { code?: string }>;
        try {
          message = JSON.parse(text) as Record<string, { code?: string }>;
        } catch (error) {
          ztoolkit.log(
            `ddos-guard: ignored non-json websocket frame: ${String(error)}`,
          );
          return;
        }
        const response: Record<string, { value: unknown }> = {};
        for (const [key, challenge] of Object.entries(message)) {
          response[key] = {
            value: this.answerChallenge(challenge.code ?? ""),
          };
        }
        batches += 1;
        ws.send(JSON.stringify(response));
      };
    });
  }

  private static answerChallenge(code: string): unknown {
    const fp = DDG_FINGERPRINT.newFp;
    if (/getAttribu|isWebDrive|webdriver/.test(code)) {
      return fp.isWebDriver;
    }
    if (
      /getHasLied/.test(code) &&
      /language|languages|userAgent|Firefox/.test(code)
    ) {
      return fp.hasLiedLanguages;
    }
    if (
      /getHasLied/.test(code) &&
      /screen|availWidth|availHeigh|Resolution/.test(code)
    ) {
      return fp.hasLiedResolution;
    }
    if (
      /screenX|screenY|isExtended|innerWidth|outerWidth|innerHeight|outerHeight/.test(
        code,
      )
    ) {
      return fp.hasLiedResolution;
    }
    if (
      /getWebglFp|VERTEX_SHA|FRAGMENT_S|gl_Posi|vertexAttr|ryinTexCoo|getAttribL/.test(
        code,
      )
    ) {
      return fp.webglFp;
    }
    if (/anisotr|ANISOTROPY|OTROPY_EXT|er_anisotr|e_filter_a/.test(code)) {
      return fp.webglAnisotropy;
    }
    if (/antialias|tialiasing|getContextAttributes/.test(code)) {
      return fp.webglAntialiasing;
    }
    if (/UNMASKED_RENDERER|webglGPU|RENDERER_WEBGL/.test(code)) {
      return fp.webglGPU;
    }
    if (/UNMASKED_VENDOR|webglVendor|VENDOR_WEBGL/.test(code)) {
      return fp.webglVendor;
    }
    if (/getAudioFp|OfflineAudio|AudioContext|getChannelData/.test(code)) {
      return fp.audioFp;
    }
    if (
      /getCanvasW/.test(code) ||
      (/isPointInP|evenodd/.test(code) && !/getCanvasF|toDataURL/.test(code))
    ) {
      return fp.canvasWinding;
    }
    if (/getCanvasF|toDataURL/.test(code)) {
      return fp.canvasFp;
    }
    if (/getFonts|offsetWidt|offsetHeigh/.test(code)) {
      return fp.fonts;
    }
    if (/getAdBlock|adBlock/.test(code)) {
      return fp.adBlock;
    }
    if (/getTouchEv|createEven/.test(code)) {
      return fp.touchSupportEvent;
    }
    if (/getTouchSt|ontouchsta/.test(code)) {
      return fp.touchSupportStart;
    }
    if (/getMaxTouc|maxTouch|msMaxTouch/.test(code)) {
      return fp.maxTouchPoints;
    }
    if (/getPluginN|plugins/.test(code)) {
      return fp.plugins;
    }
    if (
      /getSensorI|SensorApiN|Accelerome|Gyroscope|OrientationSensor|GravitySen|linearAcce|ambientLig/.test(
        code,
      )
    ) {
      return fp.sensor;
    }
    if (/getUserAge|userAgent/.test(code)) {
      return fp.userAgent;
    }
    if (/getLanguag|languages|systemLang/.test(code)) {
      return fp.languages;
    }
    if (/getPlatfor|platform/.test(code)) {
      return fp.platform;
    }
    if (/getHardwar|hardwareCo|eConcurren/.test(code)) {
      return fp.hardwareConcurrency;
    }
    if (/getDeviceM|deviceMemo|emory/.test(code)) {
      return fp.deviceMemory;
    }
    if (/getCpuClas|cpuClass/.test(code)) {
      return fp.cpuClass;
    }
    if (/getColorDe|colorDepth/.test(code)) {
      return fp.colorDepth;
    }
    if (/getPixelRa|devicePixe|lRatio/.test(code)) {
      return fp.pixelRatio;
    }
    if (/getScreenR/.test(code) && /availHeigh|vailableHe|eadHt/.test(code)) {
      return fp.availableHeight;
    }
    if (/getScreenR/.test(code) && /availWidth|vailableWi/.test(code)) {
      return fp.availableWidth;
    }
    if (/getScreenR/.test(code) && /height|eadHt|defaultHe/.test(code)) {
      return fp.defaultHeight;
    }
    if (/getScreenR/.test(code) && /width|efaultWidt|defaultWi/.test(code)) {
      return fp.defaultWidth;
    }

    ztoolkit.log(
      `ddos-guard: unknown websocket probe, returning not available; code length=${code.length}`,
    );
    return "not available";
  }

  private static randomID(length = 16): string {
    const alphabet =
      "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
    let value = "";
    for (let i = 0; i < length; i += 1) {
      value += alphabet[Math.floor(Math.random() * alphabet.length)];
    }
    return value;
  }

  private static async sleep(ms: number): Promise<void> {
    await new Promise((resolve) => setTimeout(resolve, ms));
  }
}
